// ⚠️ ВСТАВЬ СВОЙ API КЛЮЧ ANTHROPIC ЗДЕСЬ:
const ANTHROPIC_API_KEY = 'PASTE_YOUR_KEY_HERE';

const body = $input.first().json.body || $input.first().json;
const title = body.title || '';
const description = body.description || '';

const prompt = `You are a startup builder. Create a complete product brief and landing page for this SaaS idea.

Idea: ${title}
Description: ${description}

Generate a JSON response with this EXACT structure (no markdown, no extra text):
{
  "productName": "Short catchy product name",
  "tagline": "One compelling line that sells the product",
  "problem": "The painful problem this solves in 2 sentences",
  "solution": "How this product solves it in 2 sentences",
  "targetAudience": "Exactly who this is for (be specific)",
  "pricing": [{"plan": "Starter", "price": "$29/mo", "features": ["Feature 1", "Feature 2", "Feature 3"]}, {"plan": "Pro", "price": "$79/mo", "features": ["Feature 1", "Feature 2", "Feature 3", "Feature 4"]}],
  "features": ["Feature 1 with benefit", "Feature 2 with benefit", "Feature 3 with benefit", "Feature 4 with benefit", "Feature 5 with benefit", "Feature 6 with benefit"],
  "techStack": ["Next.js", "TypeScript", "Tailwind CSS", "Stripe", "Supabase"],
  "mvpSteps": [{"day": "День 1-2", "task": "Setup & Auth"}, {"day": "День 3-5", "task": "Core feature"}, {"day": "День 6-7", "task": "Payments & Launch"}],
  "landingPageHtml": "COMPLETE single-file HTML landing page with all inline CSS. Dark theme (#0a0a0a background, white text). Must include: 1) Hero section with big headline and CTA button, 2) Problem section, 3) Features grid (6 features), 4) Pricing cards (2 plans), 5) Footer. Make it beautiful and ready to publish.",
  "domain": "suggested-domain-name.com"
}`;

const response = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: {
    'x-api-key': ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json'
  },
  body: JSON.stringify({
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 4000,
    messages: [{ role: 'user', content: prompt }]
  })
});

if (!response.ok) {
  const err = await response.text();
  throw new Error('Anthropic error ' + response.status + ': ' + err);
}

const data = await response.json();
let product = null;

if (data.content && data.content[0] && data.content[0].text) {
  const text = data.content[0].text.trim();
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try { product = JSON.parse(match[0]); } catch(e) {}
  }
}

if (!product) throw new Error('Could not parse product from Claude response');

return [{
  json: {
    ...product,
    ideaId: body.ideaId,
    ideaTitle: title,
    generatedAt: new Date().toISOString()
  }
}];

const fs = require('fs');
const product = $input.first().json;

if (product.error) return [{ json: product }];

const slug = (product.productName || 'product').toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-');
const projectDir = 'C:/autonomy-launches/' + slug;

if (!fs.existsSync(projectDir)) fs.mkdirSync(projectDir, { recursive: true });

if (product.landingPageHtml) {
  fs.writeFileSync(projectDir + '/index.html', product.landingPageHtml, 'utf8');
}

const brief = { ...product };
delete brief.landingPageHtml;
fs.writeFileSync(projectDir + '/brief.json', JSON.stringify(brief, null, 2), 'utf8');

const readme = '# ' + product.productName + '\n\n' + product.tagline + '\n\n## Problem\n' + product.problem + '\n\n## Solution\n' + product.solution + '\n\n## Target Audience\n' + product.targetAudience + '\n\n## Tech Stack\n' + (product.techStack || []).join(', ') + '\n\n## MVP Steps\n' + (product.mvpSteps || []).map(s => '- **' + s.day + '**: ' + s.task).join('\n') + '\n\n## Launch Checklist\n- [ ] Buy domain: ' + product.domain + '\n- [ ] Set up Next.js project\n- [ ] Deploy to Vercel\n- [ ] Connect Stripe\n- [ ] Launch on ProductHunt\n';
fs.writeFileSync(projectDir + '/README.md', readme, 'utf8');

if (!fs.existsSync('C:/autonomy-data')) fs.mkdirSync('C:/autonomy-data', { recursive: true });
const registryPath = 'C:/autonomy-data/launches.json';
let launches = [];
try { launches = JSON.parse(fs.readFileSync(registryPath, 'utf8')); } catch(e) {}
launches.push({ id: Date.now(), ideaId: product.ideaId, ideaTitle: product.ideaTitle, productName: product.productName, tagline: product.tagline, slug, status: 'generated', projectDir, generatedAt: product.generatedAt });
fs.writeFileSync(registryPath, JSON.stringify(launches, null, 2), 'utf8');

return [{ json: { success: true, productName: product.productName, tagline: product.tagline, slug, projectDir, landingPageUrl: 'file:///' + projectDir + '/index.html', domain: product.domain, generatedAt: product.generatedAt } }];
